{{
  (() => {
    const totalVehiculos = (qCpVehiculosResumen.data || []).length;
    const planVehiculos = Number(appsmith.store.cp_total_vehiculos_booking || 0);

    if (!appsmith.store.cp_exportacion_id) return "SELECCIONE UNA OPERACIÓN.";
    if (totalVehiculos === 0) return "SIN VEHÍCULOS REGISTRADOS.";
    if (planVehiculos > 0 && totalVehiculos > planVehiculos) return "ALERTA: VEHÍCULOS REGISTRADOS SUPERAN LO PLANIFICADO.";
    if (planVehiculos > 0 && totalVehiculos < planVehiculos) return "VEHÍCULOS PENDIENTES POR REGISTRAR.";
    return "VEHÍCULOS COMPLETOS.";
  })()
}}
